import os
import boto3
import pickle
from datetime import datetime

def load_model_from_cloud(model_path):
    """Load model from cloud storage"""
    # Parse model path (assuming s3://bucket/path/to/model)
    if model_path.startswith('s3://'):
        s3 = boto3.client('s3')
        bucket = model_path.split('/')[2]
        key = '/'.join(model_path.split('/')[3:])
        
        # Get latest model by modified time
        paginator = s3.get_paginator('list_objects_v2')
        pages = paginator.paginate(Bucket=bucket, Prefix=key)
        
        latest_model = None
        latest_time = datetime.min
        
        for page in pages:
            if 'Contents' in page:
                for obj in page['Contents']:
                    if obj['Key'].endswith('.pkl') or obj['Key'].endswith('.model'):
                        if obj['LastModified'] > latest_time:
                            latest_time = obj['LastModified']
                            latest_model = obj['Key']
        
        if latest_model:
            response = s3.get_object(Bucket=bucket, Key=latest_model)
            model_data = response['Body'].read()
            return pickle.loads(model_data)
    
    return None

def main():
    model_path = os.environ.get('MODEL_PATH', '')
    if not model_path:
        raise ValueError("MODEL_PATH environment variable not set")
    
    model = load_model_from_cloud(model_path)
    if model is None:
        raise RuntimeError("Failed to load model from cloud storage")
    
    # Your inference service code here
    print("Model loaded successfully")

if __name__ == "__main__":
    main()